children.text:
@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/lambda-test/layout/data/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

.target {
  inline-size: 200px;
  padding: 10px;
  border: solid 3px;
  position: relative;
  line-height: 0;
  font-size: 20px;
  writing-mode: vertical-rl;
}

.inner {
  border: solid 5px;
  padding: 10px;
  baseline-source: last;
  font-size: 30px;
}

span {
  display: inline-block;
  width: 1em;
  height: 1em;
  outline: solid cyan 3px;
  outline-offset: -3px;
}

textarea {
  border: solid 5px;
  width: 60px;
  height: 60px;
  vertical-align: baseline;
  font-family: Ahem;
  line-height: 1;
  margin: 0;
  padding: 0;
}
